# compute longest common substring length using dynamic programming
def longest_common_substring(a,b):
    # returns length and substring
    if not a or not b:
        return 0, ""
    m = [[0]*(len(b)+1) for _ in range(len(a)+1)]
    longest = 0
    lcs_end = 0
    for i in range(1, len(a)+1):
        for j in range(1, len(b)+1):
            if a[i-1] == b[j-1]:
                m[i][j] = m[i-1][j-1] + 1
                if m[i][j] > longest:
                    longest = m[i][j]
                    lcs_end = i
            else:
                m[i][j] = 0
    return longest, a[lcs_end-longest:lcs_end]

